"use client"
import React, { useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { CheckCircle2, AlertCircle, Info, X } from 'lucide-react';
import clsx from 'clsx';

export type ToastType = 'success' | 'error' | 'info';

export interface ToastProps {
    id: string;
    message: string;
    type?: ToastType;
    persistent?: boolean;
    action?: {
        label: string;
        onClick: () => void;
    };
    onClose: (id: string) => void;
}

const Toast = ({ id, message, type = 'success', persistent = false, action, onClose }: ToastProps) => {
    useEffect(() => {
        if (!persistent) {
            const timer = setTimeout(() => {
                onClose(id);
            }, 5000);
            return () => clearTimeout(timer);
        }
    }, [id, persistent, onClose]);

    const icons = {
        success: <CheckCircle2 size={14} className="text-[#D946EF]" />,
        error: <AlertCircle size={14} className="text-red-400" />,
        info: <Info size={14} className="text-blue-400" />
    };

    return (
        <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            className={clsx(
                "flex items-center gap-3 px-4 py-3 bg-[#1C1C1E] border rounded-lg shadow-2xl min-w-[300px] max-w-md",
                type === 'success' ? "border-[#D946EF]/30" : 
                type === 'error' ? "border-red-500/30" : 
                "border-blue-500/30"
            )}
        >
            <div className="flex-shrink-0">{icons[type]}</div>
            <div className="flex-1 text-xs font-mono text-[#D8D8D8] uppercase tracking-wider flex items-center justify-between gap-4">
                <span>{message}</span>
                {action && (
                    <button 
                        onClick={(e) => {
                            e.stopPropagation();
                            action.onClick();
                        }}
                        className="flex-shrink-0 px-2.5 py-1 bg-[#1A3A3A] hover:bg-[#204A4A] border border-[#255656] text-[#D946EF] rounded text-xs font-bold uppercase tracking-widest transition-all"
                    >
                        {action.label}
                    </button>
                )}
            </div>
            <button 
                onClick={() => onClose(id)}
                className="text-[#333] hover:text-[#D8D8D8] transition-colors ml-1"
            >
                <X size={14} />
            </button>
        </motion.div>
    );
};

export const ToastContainer = ({ toasts, onClose }: { toasts: any[], onClose: (id: string) => void }) => {
    return (
        <div className="fixed bottom-6 right-6 z-[9999] flex flex-col gap-3">
            <AnimatePresence>
                {toasts.map((toast) => (
                    <Toast key={toast.id} {...toast} onClose={onClose} />
                ))}
            </AnimatePresence>
        </div>
    );
};

"use client"
import React, { useState } from "react"
import { Mail, Shield, LogOut, Key, Loader2, AlertCircle } from "lucide-react"
import { supabase } from "@/lib/supabase"
import { useRouter } from "next/navigation"

export default function AccountSection() {
    const [isUpdating, setIsUpdating] = useState(false)
    const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null)
    const router = useRouter()

    const handleLogout = async () => {
        await supabase.auth.signOut()
        router.push("/login")
    }

    const resetPassword = async () => {
        setIsUpdating(true)
        setMessage(null)
        try {
            const { data: { session } } = await supabase.auth.getSession()
            if (!session?.user?.email) throw new Error("No user email found")

            const { error } = await supabase.auth.resetPasswordForEmail(session.user.email, {
                redirectTo: `${window.location.origin}/auth/callback?next=/account?tab=account`,
            })

            if (error) throw error
            setMessage({ type: 'success', text: "Password reset link sent to your email." })
        } catch (err: any) {
            setMessage({ type: 'error', text: err.message || "Failed to send reset link." })
        } finally {
            setIsUpdating(false)
        }
    }

    return (
