                            <span className="text-xs text-[#444]">Active across 28 regions</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* DNS Configuration Section */}
            <div className="flex flex-col gap-4">
                <div className="flex items-center justify-between border-b border-[#2A2A2E] pb-2">
