"use client"
import React, { useState } from "react"
import { MoreVertical, ExternalLink, CheckCircle2, Clock, AlertTriangle, Trash2, Link2, Unlink } from "lucide-react"
import { format } from "date-fns"
import { supabase } from "@/lib/supabase"

interface DomainRowProps {
    domain: any
    onViewDetail: (id: string) => void
    onRefresh: () => void
}

export default function DomainRow({ domain, onViewDetail, onRefresh }: DomainRowProps) {
    const [isMenuOpen, setIsMenuOpen] = useState(false)
    const [isDeleting, setIsDeleting] = useState(false)

    const getStatusStyles = (status: string) => {
        switch (status?.toLowerCase()) {
            case "verified":
                return {
                    icon: <CheckCircle2 className="w-3 h-3 text-emerald-400" />,
                    text: "VERIFIED",
                    bg: "bg-emerald-500/10 text-emerald-400 border-emerald-500/20"
                }
            case "pending":
                return {
                    icon: <Clock className="w-3 h-3 text-amber-400" />,
                    text: "PENDING",
                    bg: "bg-amber-500/10 text-amber-400 border-amber-500/20"
                }
            case "failed":
            case "error":
                return {
                    icon: <AlertTriangle className="w-3 h-3 text-red-400" />,
                    text: "ERROR",
                    bg: "bg-red-500/10 text-red-400 border-red-500/20"
                }
            default:
                return {
                    icon: <div className="w-1.5 h-1.5 rounded-full bg-[#444]" />,
                    text: "UNVERIFIED",
                    bg: "bg-[#2A2A2E] text-[#666] border-[#333336]"
                }
        }
    }

    const state = getStatusStyles(domain.status)

    const handleDelete = async () => {
        if (!confirm(`Are you sure you want to remove ${domain.domain_name}?`)) return

        setIsDeleting(true)
        try {
            const { error } = await supabase
                .from("domains")
                .delete()
                .eq("id", domain.id)

            if (error) throw error
            onRefresh()
        } catch (error) {
            console.error("Error deleting domain:", error)
            alert("Failed to delete domain. Please try again.")
        } finally {
            setIsDeleting(false)
        }
    }

    return (
        <div 
            className="grid grid-cols-[1fr_120px_180px_100px_48px] items-center gap-4 px-4 py-3 bg-black hover:bg-black transition-colors border-t border-[#2A2A2E] group"
        >
            {/* Domain Name */}
            <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-md bg-[#1C1C1E] border border-[#2A2A2E] flex items-center justify-center group-hover:border-fuchsia-500/30 transition-colors">
                    <span className="text-xs font-bold text-[#444] group-hover:text-fuchsia-400 capitalize">
                        {domain.domain_name?.charAt(0) || "D"}
                    </span>
                </div>
                <div className="flex flex-col">
                    <button 
                        onClick={() => onViewDetail(domain.id)}
                        className="text-sm font-medium text-white hover:text-fuchsia-400 transition-colors text-left truncate max-w-[200px]"
                    >
                        {domain.domain_name}
                    </button>
                    {domain.is_primary && (
                        <span className="text-xs font-bold text-fuchsia-400 tracking-widest uppercase">Primary</span>
                    )}
                </div>
            </div>

            {/* Status */}
            <div>
                <div className={`inline-flex items-center gap-1.5 px-2 py-0.5 rounded border ${state.bg} text-xs font-bold tracking-wider`}>
                    {state.icon}
                    {state.text}
                </div>
            </div>

            {/* Project */}
            <div className="flex items-center gap-2">
                <div className="w-4 h-4 rounded bg-[#2A2A2E] border border-[#2A2A2E] flex items-center justify-center">
                   <Link2 className="w-2.5 h-2.5 text-[#444]" />
                </div>
                <span className="text-xs text-[#888] truncate">
                    {domain.project_name || "Internal Proxy"}
                </span>
            </div>

            {/* Date */}
            <div className="text-xs text-[#444] font-mono">
                {format(new Date(domain.created_at), "MMM d, yyyy")}
            </div>

            {/* Action Menu */}
            <div className="text-right relative">
                <button 
                    onClick={() => setIsMenuOpen(!isMenuOpen)}
                    className="p-1 hover:bg-[#2A2A2E] rounded text-[#444] hover:text-white transition-colors"
                >
                    <MoreVertical className="w-4 h-4" />
                </button>

                {isMenuOpen && (
                    <>
                        <div 
                            className="fixed inset-0 z-10" 
                            onClick={() => setIsMenuOpen(false)}
                        />
                        <div className="absolute right-0 top-full mt-1 w-48 bg-[#1C1C1E] border border-[#2A2A2E] rounded-md shadow-2xl z-20 py-1 overflow-hidden animate-in fade-in zoom-in-95 duration-100">
                            <button 
                                onClick={() => {
                                    setIsMenuOpen(false)
                                    onViewDetail(domain.id)
                                }}
                                className="w-full flex items-center gap-2 px-3 py-2 text-xs text-[#AAA] hover:text-white hover:bg-[#2A2A2E] transition-colors"
                            >
                                <ExternalLink className="w-3.5 h-3.5" />
                                View Details
                            </button>
                            <div className="h-px bg-[#2A2A2E] my-1" />
                            <button 
                                onClick={() => {
                                    setIsMenuOpen(false)
                                    handleDelete()
                                }}
                                disabled={isDeleting}
                                className="w-full flex items-center gap-2 px-3 py-2 text-xs text-red-400 hover:bg-red-500/10 transition-colors disabled:opacity-50"
                            >
                                <Trash2 className="w-3.5 h-3.5" />
                                {isDeleting ? "Removing..." : "Remove Domain"}
                            </button>
                        </div>
                    </>
                )}
            </div>
        </div>
    )
}

"use client"
import React, { useState, useEffect } from "react"
import { Globe, Plus, Loader2, ChevronLeft } from "lucide-react"
import { useSearchParams, useRouter } from "next/navigation"
import { supabase } from "@/lib/supabase"
import DomainList from "./DomainList"
import DomainDetail from "./DomainDetail"
import AddDomainWizard from "./modals/AddDomainWizard"

interface DomainsTabProps {
    projectId: string
}

import { TabHeader } from "@/components/ui/TabHeader"

export default function DomainsTab({ projectId }: DomainsTabProps) {
    const [view, setView] = useState<"list" | "detail">("list")
    const [selectedDomainId, setSelectedDomainId] = useState<string | null>(null)
    const [isLoading, setIsLoading] = useState(true)
    const [domains, setDomains] = useState<any[]>([])
    const [showAddModal, setShowAddModal] = useState(false)

    const searchParams = useSearchParams()
    const router = useRouter()
    const domainIdParam = searchParams.get("domainId")
    const addParam = searchParams.get("add")

    useEffect(() => {
        if (domainIdParam) {
            setSelectedDomainId(domainIdParam)
            setView("detail")
        }
    }, [domainIdParam])

    useEffect(() => {
        if (addParam === "true") {
            setShowAddModal(true)
            // Clear the param after opening to avoid re-opening on manual refresh/navigation
            const params = new URLSearchParams(searchParams.toString())
            params.delete("add")
            router.replace(`/project/${projectId}/domains?${params.toString()}`, { scroll: false })
        }
    }, [addParam, projectId, router, searchParams])

    useEffect(() => {
        const handleOpenAddDomain = () => setShowAddModal(true)
        window.addEventListener('open-add-domain', handleOpenAddDomain)
        return () => window.removeEventListener('open-add-domain', handleOpenAddDomain)
    }, [])

    useEffect(() => {
        fetchDomains()
    }, [projectId])

    const fetchDomains = async () => {
        setIsLoading(true)
        try {
            const { data, error } = await supabase
                .from("domains")
                .select("*")
                .eq("project_id", projectId)
                .order("created_at", { ascending: false })

            if (error) throw error
            setDomains(data || [])
        } catch (error) {
            console.error("Error fetching domains:", error)
        } finally {
            setIsLoading(false)
        }
    }

    const handleViewDetail = (id: string) => {
        setSelectedDomainId(id)
        setView("detail")
    }

    const handleBackToList = () => {
        setView("list")
        setSelectedDomainId(null)
        // Clear query param
        const params = new URLSearchParams(searchParams.toString())
        params.delete("domainId")
        router.push(`/project/${projectId}/domains?${params.toString()}`, { scroll: false })
        fetchDomains()
    }

    if (isLoading && view === "list") {
        return (
            <div className="flex items-center gap-2 text-[#444] text-sm p-8 font-mono">
                <Loader2 className="w-3.5 h-3.5 animate-spin" />
                <span>SYNCING_DOMAINS...</span>
            </div>
        )
    }

    return (
        <div className="flex flex-col gap-6 animate-in fade-in duration-500 pb-12">
            <TabHeader 
                title={view === "detail" ? "Domain Details" : "Custom Domains"}
                description={view === "detail" 
                    ? "Manage routing rules and DNS configuration for your domain." 
                    : "Connect custom domains to your project and manage SSL certificates."
                }
                backAction={view === "detail" ? { onClick: handleBackToList } : undefined}
                action={view === "list" ? {
                    label: "Add Domain",
                    onClick: () => setShowAddModal(true),
                    icon: Plus
                } : undefined}
            />

            {view === "list" ? (
                <DomainList 
                    domains={domains} 
                    onViewDetail={handleViewDetail} 
                    onRefresh={fetchDomains}
                />
            ) : (
                <DomainDetail 
                    domainId={selectedDomainId!} 
                    onBack={handleBackToList} 
                />
            )}

            {showAddModal && (
                <AddDomainWizard 
                    projectId={projectId}
                    onClose={() => setShowAddModal(false)}
                    onSuccess={() => {
                        setShowAddModal(false)
                        fetchDomains()
                    }}
                />
            )}
        </div>
    )
}

"use client"
import React, { useState } from "react"
import { MoreVertical, Edit2, Trash2, Power, Globe, ArrowRight, ExternalLink } from "lucide-react"
import { supabase } from "@/lib/supabase"
import EditRouteModal from "./modals/EditRouteModal"

interface RouteCardProps {
    route: any
    onRefresh: () => void
}

export default function RouteCard({ route, onRefresh }: RouteCardProps) {
    const [isMenuOpen, setIsMenuOpen] = useState(false)
    const [isUpdating, setIsUpdating] = useState(false)
    const [showEditModal, setShowEditModal] = useState(false)

    const handleToggle = async () => {
        setIsUpdating(true)
        try {
            const { error } = await supabase
                .from("domain_routes")
                .update({ is_active: !route.is_active })
                .eq("id", route.id)

            if (error) throw error
            onRefresh()
        } catch (error) {
            console.error("Error toggling route:", error)
        } finally {
            setIsUpdating(false)
        }
    }

    const handleDelete = async () => {
        if (!confirm(`Are you sure you want to delete the route for ${route.path}?`)) return

        setIsUpdating(true)
        try {
            const { error } = await supabase
                .from("domain_routes")
                .delete()
                .eq("id", route.id)

            if (error) throw error
            onRefresh()
        } catch (error) {
            console.error("Error deleting route:", error)
        } finally {
            setIsUpdating(false)
        }
    }

    return (
        <div 
            className={`p-3 bg-black border rounded-lg transition-all group ${
                route.is_active ? "border-[#2A2A2E] hover:border-[#333336]" : "border-[#2A2A2E] opacity-60"
            }`}
        >
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <div className={`w-8 h-8 rounded-md flex items-center justify-center border ${
                        route.is_active ? "bg-fuchsia-500/5 border-fuchsia-500/20 text-fuchsia-400" : "bg-[#2A2A2E] border-[#333336] text-[#444]"
                    }`}>
                        <Globe className="w-4 h-4" />
                    </div>

                    <div className="flex flex-col">
                        <div className="flex items-center gap-2">
                            <span className="text-sm font-mono text-white">{route.path || "/"}</span>
                            <ArrowRight className="w-3 h-3 text-[#333]" />
                            <span className="text-sm font-mono text-[#888]">Port {route.target_port}</span>
                        </div>
                        <div className="flex items-center gap-1.5 mt-0.5">
                            <div className={`w-1.5 h-1.5 rounded-full ${route.is_active ? "bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.3)]" : "bg-[#333]"}`} />
                            <span className="text-xs font-bold text-[#444] uppercase tracking-widest">
                                {route.is_active ? "ACTIVE_ROUTING" : "DISABLED"}
                            </span>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={handleToggle}
                        disabled={isUpdating}
                        className={`p-1.5 rounded transition-colors ${
                            route.is_active 
                                ? "text-[#444] hover:text-amber-400 hover:bg-amber-500/10" 
                                : "text-emerald-400 bg-emerald-500/10 hover:bg-emerald-500/20"
                        }`}
                        title={route.is_active ? "Disable Route" : "Enable Route"}
                    >
                        <Power className="w-3.5 h-3.5" />
                    </button>

                    <div className="relative">
                        <button 
                            onClick={() => setIsMenuOpen(!isMenuOpen)}
                            className="p-1.5 hover:bg-[#2A2A2E] rounded text-[#444] hover:text-white transition-colors"
                        >
                            <MoreVertical className="w-4 h-4" />
                        </button>

                        {isMenuOpen && (
                            <>
                                <div 
                                    className="fixed inset-0 z-10" 
                                    onClick={() => setIsMenuOpen(false)}
                                />
                                <div className="absolute right-0 top-full mt-1 w-36 bg-[#1C1C1E] border border-[#2A2A2E] rounded-md shadow-2xl z-20 py-1 overflow-hidden">
                                    <button 
                                        onClick={() => {
                                            setIsMenuOpen(false)
                                            setShowEditModal(true)
                                        }}
                                        className="w-full flex items-center gap-2 px-3 py-2 text-xs text-[#AAA] hover:text-white hover:bg-[#2A2A2E] transition-colors"
                                    >
                                        <Edit2 className="w-3.5 h-3.5" />
                                        Edit
                                    </button>
                                    <button 
                                        onClick={() => {
                                            setIsMenuOpen(false)
                                            handleDelete()
                                        }}
                                        className="w-full flex items-center gap-2 px-3 py-2 text-xs text-red-400 hover:bg-red-500/10 transition-colors"
                                    >
                                        <Trash2 className="w-3.5 h-3.5" />
                                        Delete
                                    </button>
                                </div>
                            </>
                        )}
                    </div>
                </div>
            </div>

            {showEditModal && (
                <EditRouteModal 
                    route={route}
                    onClose={() => setShowEditModal(false)}
                    onSuccess={() => {
                        setShowEditModal(false)
                        onRefresh()
                    }}
                />
            )}
        </div>
    )
}

"use client"
import React, { useState } from "react"
import { createPortal } from "react-dom"
import { motion } from "framer-motion"
import { X, ArrowRight, Loader2, Link2, Info, AlertCircle } from "lucide-react"
import { supabase } from "@/lib/supabase"

interface AddRouteModalProps {
    domainId: string
    onClose: () => void
    onSuccess: () => void
}

export default function AddRouteModal({ domainId, onClose, onSuccess }: AddRouteModalProps) {
    const [path, setPath] = useState("/")
    const [targetPort, setTargetPort] = useState("3000")
    const [isSubmitting, setIsSubmitting] = useState(false)
    const [error, setError] = useState<string | null>(null)

    const handleAdd = async () => {
        if (!path || !targetPort) return
        setError(null)
        setIsSubmitting(true)

        try {
            // Validation
            if (!path.startsWith("/")) {
                throw new Error("Path must start with /")
            }

            const portNum = parseInt(targetPort)
            if (isNaN(portNum) || portNum < 1 || portNum > 65535) {
                throw new Error("Invalid target port (1-65535)")
            }

            const { error: insertError } = await supabase
                .from("domain_routes")
                .insert({
                    domain_id: domainId,
                    path: path,
                    target_port: portNum,
                    is_active: true
                })

            if (insertError) {
                if (insertError.code === "23505") {
                    throw new Error("A route with this path already exists for this domain.")
                }
                throw insertError
            }

            onSuccess()
        } catch (err: any) {
            setError(err.message || "Failed to add route")
        } finally {
            setIsSubmitting(false)
        }
    }

    return createPortal(
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
            <motion.div 
                initial={{ opacity: 0, scale: 0.95, y: 10 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                className="w-full max-w-md bg-black border border-[#2A2A2E] rounded-xl shadow-2xl overflow-hidden"
            >
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b border-[#2A2A2E]">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-lg bg-[#2A2A2E] flex items-center justify-center border border-[#2A2A2E]">
                            <Link2 className="w-4 h-4 text-fuchsia-400" />
                        </div>
                        <h3 className="text-white font-bold uppercase tracking-widest text-sm">Add Routing Rule</h3>
                    </div>
                    <button onClick={onClose} className="p-1.5 hover:bg-[#2A2A2E] rounded-md text-[#444] hover:text-white transition-colors">
                        <X className="w-4 h-4" />
                    </button>
                </div>

                <div className="p-6 flex flex-col gap-6">
                    <div className="flex flex-col gap-4">
                        <div className="flex flex-col gap-2">
                             <label className="text-xs font-bold text-[#666] uppercase tracking-wider">Public Path</label>
                             <div className="relative">
                                <input 
                                    autoFocus
                                    type="text"
                                    placeholder="/"
                                    value={path}
                                    onChange={(e) => setPath(e.target.value)}
                                    className="w-full bg-[#1C1C1E] border border-[#2A2A2E] rounded-md px-4 py-3 text-white text-base focus:outline-none focus:border-fuchsia-500/50 transition-colors font-mono"
                                />
                             </div>
                             <p className="text-xs text-[#444]">The external URL path (e.g. /, /api, /blog)</p>
                        </div>

                        <div className="flex flex-col gap-2">
                             <label className="text-xs font-bold text-[#666] uppercase tracking-wider">Internal Port</label>
                             <input 
                                type="text"
                                placeholder="3000"
                                value={targetPort}
                                onChange={(e) => setTargetPort(e.target.value)}
                                className="w-full bg-[#1C1C1E] border border-[#2A2A2E] rounded-md px-4 py-3 text-white text-base focus:outline-none focus:border-fuchsia-500/50 transition-colors font-mono"
                             />
                             <p className="text-xs text-[#444]">The port where your application is running inside the container.</p>
                        </div>
                    </div>

                    {error && (
                        <div className="p-3 bg-red-500/10 border border-red-500/20 rounded flex items-start gap-3">
                            <AlertCircle className="w-4 h-4 text-red-500 shrink-0 mt-0.5" />
                            <span className="text-xs text-red-400">{error}</span>
                        </div>
                    )}

                    <div className="flex justify-end gap-3 mt-2">
                        <button 
                            onClick={onClose}
                            className="px-4 py-2 text-[#666] hover:text-white text-sm font-medium transition-colors"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={handleAdd}
                            disabled={isSubmitting}
                            className="px-6 py-2 bg-fuchsia-500/10 hover:bg-fuchsia-500/20 text-fuchsia-400 border border-fuchsia-500/30 rounded font-bold uppercase tracking-widest text-xs transition-all disabled:opacity-50 flex items-center gap-2"
                        >
