                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        {appStoreStatus.isReady ? (
                            <div className="px-3 py-1 bg-green-500/10 border border-green-500/20 text-green-500 text-[10px] font-bold rounded-full">READY</div>
                        ) : (
