                            <button
                                onClick={handleToggleAppStore}
                                disabled={isUpdating || !appStoreStatus.isReady}
                                className={clsx(
                                    "relative w-10 h-5 rounded-full transition-all",
                                    appStoreEnabled ? "bg-[#E91E63]" : "bg-[#1C1C1E]"
