import { Terminal } from 'xterm';
import { supabase } from '@/lib/supabase';

export class TerminalEngine {
  private terminal: Terminal;
  private history: string[] = [];
  private historyIndex = -1;

  constructor(terminal: Terminal) {
    this.terminal = terminal;
    this.loadHistory();
  }

  private loadHistory() {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('foldaa_terminal_history');
      if (saved) {
        this.history = JSON.parse(saved);
      }
    }
  }

  private saveHistory(command: string) {
    if (command && this.history[0] !== command) {
      this.history.unshift(command);
      if (this.history.length > 50) this.history.pop();
      localStorage.setItem('foldaa_terminal_history', JSON.stringify(this.history));
    }
    this.historyIndex = -1;
  }

  getPreviousHistory(): string | null {
    if (this.history.length === 0) return null;
    if (this.historyIndex < this.history.length - 1) {
      this.historyIndex++;
      return this.history[this.historyIndex];
    }
    return null;
  }

  getNextHistory(): string | null {
    if (this.historyIndex > 0) {
      this.historyIndex--;
      return this.history[this.historyIndex];
    } else if (this.historyIndex === 0) {
      this.historyIndex = -1;
      return '';
    }
    return null;
  }

  getSuggestion(input: string): string | null {
    if (!input || input.trim() === '') return null;

    // Find the most recent command that starts with the input
    const suggestion = this.history.find(cmd => 
      cmd.toLowerCase().startsWith(input.toLowerCase()) && 
      cmd.toLowerCase() !== input.toLowerCase()
    );

    return suggestion || null;
  }

  async execute(input: string, onProgress?: (data: any) => void): Promise<any> {
    const trimmedInput = input.trim().toLowerCase();

    // Local command interception
    if (trimmedInput === 'clear' || trimmedInput === 'cls') {
      this.saveHistory(input);
      return { success: true, local: 'clear' };
    }

    this.saveHistory(input);

    try {
      const { data: { session } } = await supabase.auth.getSession();

      const res = await fetch('/api/foldaa/command', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          ...(session?.access_token ? { 'Authorization': `Bearer ${session.access_token}` } : {})
        },
        body: JSON.stringify({ command: input })
      });

      if (!res.ok) {
        const errorData = await res.json().catch(() => ({}));
        return { success: false, error: errorData.error || `HTTP Error ${res.status}` };
      }

      if (!res.body) {
         return { success: false, error: 'No response from server' };
      }

      const reader = res.body.getReader();
      const decoder = new TextEncoder();
      let buffer = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += new TextDecoder().decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        for (const line of lines) {
          if (!line.trim()) continue;
          try {
            const msg = JSON.parse(line);

            if (onProgress && msg.event !== 'done' && msg.event !== 'error') {
              onProgress(msg);
            }

            if (msg.event === 'done') {
              return msg.result;
            } else if (msg.event === 'error') {
              return { success: false, error: msg.data };
            }
          } catch (e) {
             // Invalid chunk
          }
        }
      }

      return { success: true };
    } catch (err: any) {
        console.error('Terminal Execution Error:', err);
        return { success: false, error: err.message || 'Network error' };
    }
  }
}

"use client"
import React, { useEffect, useState } from 'react';
import { X, Terminal } from 'lucide-react';
import clsx from 'clsx';
import { motion, AnimatePresence } from 'framer-motion';

interface TerminalModalProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    children: React.ReactNode;
    footer?: React.ReactNode;
    maxWidth?: string;
}

export const TerminalModal: React.FC<TerminalModalProps> = ({
    isOpen,
    onClose,
    title,
    children,
    footer,
    maxWidth = "max-w-lg"
}) => {
    // Handle Escape key
    useEffect(() => {
        const handleEscape = (e: KeyboardEvent) => {
            if (e.key === 'Escape') onClose();
        };
        if (isOpen) {
            window.addEventListener('keydown', handleEscape);
            document.body.style.overflow = 'hidden';
        }
        return () => {
            window.removeEventListener('keydown', handleEscape);
            document.body.style.overflow = 'unset';
        };
    }, [isOpen, onClose]);

    return (
        <AnimatePresence>
            {isOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6">
                    {/* Backdrop */}
                    <motion.div 
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="absolute inset-0 bg-black/80 backdrop-blur-sm"
                    />

                    {/* Modal Content */}
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95, y: 10 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.95, y: 10 }}
                        className={clsx(
                            "relative w-full bg-[#1C1C1E] border border-[#2A2A2E] rounded-lg shadow-2xl flex flex-col overflow-hidden",
                            maxWidth
                        )}
                    >
                        {/* Header */}
                        <div className="flex items-center justify-between px-4 py-3 border-b border-[#2A2A2E] bg-black/40">
                            <div className="flex items-center gap-2">
                                <Terminal className="w-4 h-4 text-fuchsia-500/60" />
                                <span className="text-xs font-bold text-[#D8D8D8] tracking-widest uppercase font-mono">
                                    {title}
                                </span>
                            </div>
                            <button 
                                onClick={onClose}
                                className="text-[#444] hover:text-white transition-colors p-1"
                            >
                                <X className="w-4 h-4" />
                            </button>
                        </div>

                        {/* Body */}
                        <div className="p-6 overflow-y-auto custom-scrollbar">
                            {children}
                        </div>

                        {/* Footer */}
                        {footer && (
                            <div className="px-6 py-4 border-t border-[#2A2A2E] bg-black/20 flex justify-end gap-3">
                                {footer}
