"use client"
import React, { createContext, useContext, useState, useEffect } from "react";

interface UIContextType {
    isSidebarOpen: boolean;
    toggleSidebar: () => void;
    setSidebarOpen: (open: boolean) => void;
    isCreateModalOpen: boolean;
    setCreateModalOpen: (open: boolean) => void;
    toasts: any[];
    addToast: (message: string, type?: 'success' | 'error' | 'info', persistent?: boolean) => void;
    removeToast: (id: string) => void;
}

const UIContext = createContext<UIContextType | undefined>(undefined);

export function UIProvider({ children }: { children: React.ReactNode }) {
    const [isSidebarOpen, setSidebarOpen] = useState(true);
    const [isCreateModalOpen, setCreateModalOpen] = useState(false);
    const [toasts, setToasts] = useState<any[]>([]);

    // Initialize from localStorage if available
    useEffect(() => {
        const saved = localStorage.getItem("sidebar_open");
        if (saved !== null) {
            setSidebarOpen(saved === "true");
        }
    }, []);

    const toggleSidebar = () => {
        setSidebarOpen(prev => {
            const newState = !prev;
            localStorage.setItem("sidebar_open", String(newState));
            return newState;
        });
    };

    const addToast = (message: string, type: 'success' | 'error' | 'info' = 'success', persistent = false) => {
        const id = Math.random().toString(36).substring(2, 9);
        setToasts(prev => [...prev, { id, message, type, persistent }]);
    };

    const removeToast = (id: string) => {
        setToasts(prev => prev.filter(t => t.id !== id));
    };

    return (
        <UIContext.Provider value={{ 
            isSidebarOpen, 
            toggleSidebar, 
            setSidebarOpen,
            isCreateModalOpen,
            setCreateModalOpen,
            toasts,
            addToast,
            removeToast
        }}>
            {children}
        </UIContext.Provider>
    );
}

export function useUI() {
    const context = useContext(UIContext);
    if (context === undefined) {
        throw new Error("useUI must be used within a UIProvider");
    }
    return context;
}

"use client"
import React, { createContext, useContext, useState, useEffect, ReactNode } from "react";
import { supabase } from "@/lib/supabase";
import { UserProfile, UserSettings } from "@/lib/hooks/useUserProfile";

type UserContextType = {
    profile: UserProfile | null;
    settings: UserSettings | null;
    loading: boolean;
    saving: boolean;
    error: any;
    updateProfile: (updates: Partial<UserProfile>) => Promise<{ success: boolean; error?: any }>;
    updateSettings: (updates: Partial<UserSettings>) => Promise<{ success: boolean; error?: any }>;
    refreshData: () => Promise<void>;
};

const UserContext = createContext<UserContextType | undefined>(undefined);

export function UserProvider({ children }: { children: ReactNode }) {
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [settings, setSettings] = useState<UserSettings | null>(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState<any>(null);

    const fetchData = async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) {
            setLoading(false);
            return;
        }

        const userId = session.user.id;
        const userMetadata = session.user.user_metadata || {};

        try {
            // Fetch profile
            const { data: profileData, error: profileError } = await supabase
                .from('profiles')
                .select('*')
                .eq('id', userId)
                .single();

            if (profileError && profileError.code !== 'PGRST116') throw profileError;

            // Fetch settings
            const { data: settingsData, error: settingsError } = await supabase
                .from('user_settings')
                .select('*')
                .eq('user_id', userId)
                .single();

            if (settingsError && settingsError.code !== 'PGRST116') throw settingsError;

            // Fetch active subscription
            const { data: licenseData } = await supabase
                .from('user_licenses')
                .select('plan_type, expires_at')
                .eq('user_id', userId)
                .eq('status', 'active')
                .order('created_at', { ascending: false })
                .limit(1)
                .maybeSingle();

            let subscriptionPlan: 'free' | 'pro' = 'free';
            if (licenseData) {
                if (!licenseData.expires_at || new Date() < new Date(licenseData.expires_at)) {
                    subscriptionPlan = licenseData.plan_type as 'free' | 'pro';
                }
            }

            // Merge profile with auth metadata for fallbacks
            const mergedProfile = {
                id: userId,
                email: session.user.email || null,
                ...profileData,
                // Fallbacks from auth metadata
                avatar_url: profileData?.avatar_url || userMetadata.avatar_url || userMetadata.picture || null,
                first_name: profileData?.first_name || userMetadata.full_name?.split(' ')[0] || userMetadata.name?.split(' ')[0] || null,
                last_name: profileData?.last_name || userMetadata.full_name?.split(' ').slice(1).join(' ') || userMetadata.name?.split(' ').slice(1).join(' ') || null,
                username: profileData?.username || userMetadata.user_name || userMetadata.preferred_username || null,
                subscriptionPlan,
            };

            setProfile(mergedProfile as UserProfile);
            setSettings(settingsData || null);
        } catch (err) {
            console.error("Error fetching user data in Context:", err);
            setError(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, []);

    const updateProfile = async (updates: Partial<UserProfile>) => {
        setSaving(true);
        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error("No session");

            const { error } = await supabase
                .from('profiles')
                .upsert({ ...updates, id: session.user.id, updated_at: new Date().toISOString() });

            if (error) throw error;
            setProfile(prev => prev ? { ...prev, ...updates } : updates as UserProfile);
            return { success: true };
        } catch (err) {
            console.error("Error updating profile:", err);
            return { success: false, error: err };
        } finally {
            setSaving(false);
        }
    };

    const updateSettings = async (updates: Partial<UserSettings>) => {
        setSaving(true);
        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error("No session");

            const { error } = await supabase
                .from('user_settings')
                .upsert({ ...updates, user_id: session.user.id, updated_at: new Date().toISOString() });

            if (error) throw error;
            setSettings(prev => prev ? { ...prev, ...updates } : updates as UserSettings);
            return { success: true };
        } catch (err) {
            console.error("Error updating settings:", err);
            return { success: false, error: err };
        } finally {
            setSaving(false);
        }
    };

    return (
        <UserContext.Provider value={{ 
            profile, 
            settings, 
            loading, 
            saving, 
            error, 
            updateProfile, 
            updateSettings,
            refreshData: fetchData 
        }}>
            {children}
        </UserContext.Provider>
    );
}

export function useUser() {
    const context = useContext(UserContext);
    if (context === undefined) {
        throw new Error('useUser must be used within a UserProvider');
    }
    return context;
}

"use client"
import { useState, useEffect } from "react";
import { supabase } from "@/lib/supabase";

export type Domain = {
    id: string;
    domain_name: string;
    status: 'pending' | 'verified' | 'failed';
    verification_method: string;
    ssl_status: string;
    created_at: string;
    updated_at: string;
    project_id: string | null;
    user_id: string;
}

export function useDomains() {
    const [domains, setDomains] = useState<Domain[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<any>(null);

    useEffect(() => {
        let isMounted = true;

        const fetchDomains = async () => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) return;

            const { data, error } = await supabase
                .from('domains')
                .select('*')
                .eq('user_id', session.user.id)
                .order('created_at', { ascending: false });

            if (error) {
                console.error("Error fetching domains:", error);
                if (isMounted) setError(error);
            } else if (isMounted) {
                setDomains(data || []);
            }
            if (isMounted) setLoading(false);
        };

        fetchDomains();

        // Subscribe to real-time changes
        const subscription = supabase
            .channel('domains_changes')
            .on('postgres_changes', {
                event: '*',
                schema: 'public',
                table: 'domains'
            }, (payload) => {
                if (payload.eventType === 'INSERT') {
                    setDomains(prev => [payload.new as Domain, ...prev]);
                } else if (payload.eventType === 'UPDATE') {
                    setDomains(prev => prev.map(d => d.id === payload.new.id ? payload.new as Domain : d));
                } else if (payload.eventType === 'DELETE') {
                    setDomains(prev => prev.filter(d => d.id === payload.old.id));
                }
            })
            .subscribe();

        return () => {
            isMounted = false;
            supabase.removeChannel(subscription);
        };
    }, []);

    return { domains, loading, error };
}

